package com.maum.backend.repository.user

import com.maum.backend.entity.user.UserEntity
import org.springframework.data.jpa.repository.JpaRepository

interface UserRepository : JpaRepository<UserEntity, String> {
    fun findByNickname(nickname: String): UserEntity?
}

package com.maum.backend.exception

class UserNotFoundException(userId: String) :
    RuntimeException("유저를 찾을 수 없습니다: $userId")

package com.maum.backend.exception

class AlreadyFollowingException(followerId: String, followingId: String) :
    RuntimeException("이미 팔로우한 유저입니다: $followerId -> $followingId")

package com.maum.backend.exception

class SelfFollowException(userId: String) :
    RuntimeException("자기 자신을 팔로우할 수 없습니다: $userId")

package com.maum.backend.exception

class NotFollowingException(followerId: String, followingId: String) :
    RuntimeException("팔로우 관계가 존재하지 않습니다: $followerId -> $followingId")

package com.maum.backend.service.user

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.exception.UserNotFoundException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    /**
     * 특정 유저 조회
     */
    fun getUser(userId: String): UserEntity {
        return userRepository.findById(userId).orElseThrow {
            UserNotFoundException(userId)
        }
    }

    /**
     * 팔로우 실행
     * - 자기 자신 팔로우 불가
     * - 대상 유저가 존재해야 함
     * - 이미 팔로우한 유저는 다시 팔로우 불가
     */
    @Transactional
    fun follow(followerId: String, followingId: String): FollowEntity {
        if (followerId == followingId) {
            throw SelfFollowException(followerId)
        }

        // 팔로우 대상 유저 존재 여부 확인
        if (!userRepository.existsById(followingId)) {
            throw UserNotFoundException(followingId)
        }

        // 이미 팔로우 중인지 확인
        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException(followerId, followingId)
        }

        val follow = FollowEntity(
            followerId = followerId,
            followingId = followingId,
        )
        return followRepository.save(follow)
    }

    /**
     * 언팔로우 실행
     * - 팔로우 관계가 존재해야 함
     */
    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NotFollowingException(followerId, followingId)

        followRepository.delete(follow)
    }

    /**
     * 팔로우 여부 확인
     */
    fun isFollowing(followerId: String, followingId: String): Boolean {
        return followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)
    }

    /**
     * 팔로잉 목록 조회 (내가 팔로우하는 사람들)
     */
    fun getFollowingList(userId: String): List<FollowEntity> {
        return followRepository.findAllByFollowerId(userId)
    }

    /**
     * 팔로워 목록 조회 (나를 팔로우하는 사람들)
     */
    fun getFollowerList(userId: String): List<FollowEntity> {
        return followRepository.findAllByFollowingId(userId)
    }

    /**
     * 팔로잉 수 조회
     */
    fun getFollowingCount(userId: String): Long {
        return followRepository.countByFollowerId(userId)
    }

    /**
     * 팔로워 수 조회
     */
    fun getFollowerCount(userId: String): Long {
        return followRepository.countByFollowingId(userId)
    }
}

package com.maum.backend.service.user

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.entity.user.UserEntity
import com.maum.backend.exception.AlreadyFollowingException
import com.maum.backend.exception.NotFollowingException
import com.maum.backend.exception.SelfFollowException
import com.maum.backend.exception.UserNotFoundException
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import org.junit.jupiter.api.extension.ExtendWith
import org.mockito.InjectMocks
import org.mockito.Mock
import org.mockito.Mockito.never
import org.mockito.Mockito.verify
import org.mockito.Mockito.`when`
import org.mockito.junit.jupiter.MockitoExtension
import org.mockito.kotlin.any
import org.mockito.kotlin.argumentCaptor
import java.util.Optional

@ExtendWith(MockitoExtension::class)
class UserServiceTest {

    @Mock
    private lateinit var userRepository: UserRepository

    @Mock
    private lateinit var followRepository: FollowRepository

    @InjectMocks
    private lateinit var userService: UserService

    // ===========================
    // getUser 테스트
    // ===========================

    @Test
    fun `should return user when user exists`() {
        // given
        val userId = "user-001"
        val userEntity = UserEntity(id = userId, nickname = "테스터")
        `when`(userRepository.findById(userId)).thenReturn(Optional.of(userEntity))

        // when
        val result = userService.getUser(userId)

        // then
        assertThat(result.id).isEqualTo(userId)
        assertThat(result.nickname).isEqualTo("테스터")
        verify(userRepository).findById(userId)
    }

    @Test
    fun `should throw UserNotFoundException when user does not exist`() {
        // given
        val userId = "non-existent-user"
        `when`(userRepository.findById(userId)).thenReturn(Optional.empty())

        // when & then
        assertThrows<UserNotFoundException> {
            userService.getUser(userId)
        }
        verify(userRepository).findById(userId)
    }

    // ===========================
    // follow 테스트
    // ===========================

    @Test
    fun `should follow successfully when valid follower and following`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        val savedFollow = FollowEntity(
            id = "follow-001",
            followerId = followerId,
            followingId = followingId,
        )
        `when`(userRepository.existsById(followingId)).thenReturn(true)
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)
        `when`(followRepository.save(any())).thenReturn(savedFollow)

        // when
        val result = userService.follow(followerId, followingId)

        // then
        assertThat(result.followerId).isEqualTo(followerId)
        assertThat(result.followingId).isEqualTo(followingId)

        val captor = argumentCaptor<FollowEntity>()
        verify(followRepository).save(captor.capture())
        assertThat(captor.firstValue.followerId).isEqualTo(followerId)
        assertThat(captor.firstValue.followingId).isEqualTo(followingId)
    }

    @Test
    fun `should throw SelfFollowException when follower and following are same`() {
        // given
        val userId = "user-001"

        // when & then
        assertThrows<SelfFollowException> {
            userService.follow(userId, userId)
        }

        // 자기 자신 팔로우 시 DB 조회 없이 즉시 예외 발생해야 함
        verify(userRepository, never()).existsById(any())
        verify(followRepository, never()).existsByFollowerIdAndFollowingId(any(), any())
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw UserNotFoundException when following user does not exist`() {
        // given
        val followerId = "user-001"
        val followingId = "non-existent-user"
        `when`(userRepository.existsById(followingId)).thenReturn(false)

        // when & then
        assertThrows<UserNotFoundException> {
            userService.follow(followerId, followingId)
        }

        verify(userRepository).existsById(followingId)
        verify(followRepository, never()).existsByFollowerIdAndFollowingId(any(), any())
        verify(followRepository, never()).save(any())
    }

    @Test
    fun `should throw AlreadyFollowingException when already following`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        `when`(userRepository.existsById(followingId)).thenReturn(true)
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when & then
        assertThrows<AlreadyFollowingException> {
            userService.follow(followerId, followingId)
        }

        verify(followRepository, never()).save(any())
    }

    // ===========================
    // unfollow 테스트
    // ===========================

    @Test
    fun `should unfollow successfully when follow relation exists`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        val existingFollow = FollowEntity(
            id = "follow-001",
            followerId = followerId,
            followingId = followingId,
        )
        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(existingFollow)

        // when
        userService.unfollow(followerId, followingId)

        // then
        verify(followRepository).findByFollowerIdAndFollowingId(followerId, followingId)
        verify(followRepository).delete(existingFollow)
    }

    @Test
    fun `should throw NotFollowingException when follow relation does not exist`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        `when`(followRepository.findByFollowerIdAndFollowingId(followerId, followingId))
            .thenReturn(null)

        // when & then
        assertThrows<NotFollowingException> {
            userService.unfollow(followerId, followingId)
        }

        verify(followRepository, never()).delete(any<FollowEntity>())
    }

    // ===========================
    // isFollowing 테스트
    // ===========================

    @Test
    fun `should return true when following relation exists`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(true)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isTrue()
        verify(followRepository).existsByFollowerIdAndFollowingId(followerId, followingId)
    }

    @Test
    fun `should return false when following relation does not exist`() {
        // given
        val followerId = "user-001"
        val followingId = "user-002"
        `when`(followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)).thenReturn(false)

        // when
        val result = userService.isFollowing(followerId, followingId)

        // then
        assertThat(result).isFalse()
    }

    // ===========================
    // getFollowingList 테스트
    // ===========================

    @Test
    fun `should return following list when user has followings`() {
        // given
        val userId = "user-001"
        val followings = listOf(
            FollowEntity(id = "follow-001", followerId = userId, followingId = "user-002"),
            FollowEntity(id = "follow-002", followerId = userId, followingId = "user-003"),
        )
        `when`(followRepository.findAllByFollowerId(userId)).thenReturn(followings)

        // when
        val result = userService.getFollowingList(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followingId }).containsExactlyInAnyOrder("user-002", "user-003")
        verify(followRepository).findAllByFollowerId(userId)
    }

    @Test
    fun `should return empty list when user has no followings`() {
        // given
        val userId = "user-001"
        `when`(followRepository.findAllByFollowerId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowingList(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ===========================
    // getFollowerList 테스트
    // ===========================

    @Test
    fun `should return follower list when user has followers`() {
        // given
        val userId = "user-002"
        val followers = listOf(
            FollowEntity(id = "follow-001", followerId = "user-001", followingId = userId),
            FollowEntity(id = "follow-002", followerId = "user-003", followingId = userId),
        )
        `when`(followRepository.findAllByFollowingId(userId)).thenReturn(followers)

        // when
        val result = userService.getFollowerList(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result.map { it.followerId }).containsExactlyInAnyOrder("user-001", "user-003")
        verify(followRepository).findAllByFollowingId(userId)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = "user-002"
        `when`(followRepository.findAllByFollowingId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowerList(userId)

        // then
        assertThat(result).isEmpty()
    }

    // ===========================
    // getFollowingCount / getFollowerCount 테스트
    // ===========================

    @Test
    fun `should return correct following count`() {
        // given
        val userId = "user-001"
        `when`(followRepository.countByFollowerId(userId)).thenReturn(5L)

        // when
        val result = userService.getFollowingCount(userId)

        // then
        assertThat(result).isEqualTo(5L)
        verify(followRepository).countByFollowerId(userId)
    }

    @Test
    fun `should return zero when user has no followings`() {
        // given
        val userId = "user-001"
        `when`(followRepository.countByFollowerId(userId)).thenReturn(0L)

        // when
        val result = userService.getFollowingCount(userId)

        // then
        assertThat(result).isZero()
    }

    @Test
    fun `should return correct follower count`() {
        // given
        val userId = "user-002"
        `when`(followRepository.countByFollowingId(userId)).thenReturn(10L)

        // when
        val result = userService.getFollowerCount(userId)

        // then
        assertThat(result).isEqualTo(10L)
        verify(followRepository).countByFollowingId(userId)
    }

    @Test
    fun `should return zero when user has no followers`() {
        // given
        val userId = "user-002"
        `when`(followRepository.countByFollowingId(userId)).thenReturn(0L)

        // when
        val result = userService.getFollowerCount(userId)

        // then
        assertThat(result).isZero()
    }
}

