import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {
    fun getUser(userId: String): UserEntity {
        return userRepository.findById(userId).orElseThrow {
            UserNotFoundException(userId)
        }
    }

    @Transactional
    fun follow(followerId: String, followingId: String): FollowEntity {
        if (followerId == followingId) throw SelfFollowException(followerId)
        if (!userRepository.existsById(followingId)) throw UserNotFoundException(followingId)
        if (followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)) {
            throw AlreadyFollowingException(followerId, followingId)
        }
        return followRepository.save(FollowEntity(followerId = followerId, followingId = followingId))
    }

    @Transactional
    fun unfollow(followerId: String, followingId: String) {
        val follow = followRepository.findByFollowerIdAndFollowingId(followerId, followingId)
            ?: throw NotFollowingException(followerId, followingId)
        followRepository.delete(follow)
    }

    fun isFollowing(followerId: String, followingId: String): Boolean =
        followRepository.existsByFollowerIdAndFollowingId(followerId, followingId)

    fun getFollowingList(userId: String): List<FollowEntity> =
